# -*- coding: utf-8 -*-
"""Test script to verify the hooks list bug fix"""

import requests

# Create some simple hook functions
def hook1(r):
    print("Hook 1 called")
    return r

def hook2(r):
    print("Hook 2 called")
    return r

def hook3(r):
    print("Hook 3 called")
    return r

# Test 1: Single hook (should work before and after fix)
print("Test 1: Single hook function")
try:
    r = requests.Request('GET', 'http://httpbin.org/get', hooks={'pre_request': hook1})
    print("✓ Single hook works")
except Exception as e:
    print(f"✗ Single hook failed: {e}")

# Test 2: List of hooks (this is the bug we're fixing)
print("\nTest 2: List of hook functions")
try:
    r = requests.Request('GET', 'http://httpbin.org/get', hooks={'pre_request': [hook1, hook2, hook3]})
    print("✓ List of hooks works")
    print(f"  Hooks registered: {r.hooks['pre_request']}")
    # Verify all hooks are callable
    for hook in r.hooks['pre_request']:
        if not callable(hook):
            raise Exception(f"Hook {hook} is not callable!")
    print("  All hooks are callable")
except Exception as e:
    print(f"✗ List of hooks failed: {e}")

# Test 3: Mixed hooks (dict with some lists, some single functions)
print("\nTest 3: Mixed hooks (some lists, some single)")
try:
    r = requests.Request('GET', 'http://httpbin.org/get', hooks={
        'pre_request': [hook1, hook2],
        'pre_send': hook3
    })
    print("✓ Mixed hooks work")
    print(f"  pre_request hooks: {r.hooks['pre_request']}")
    print(f"  pre_send hooks: {r.hooks['pre_send']}")
    # Verify all hooks are callable
    for event in ['pre_request', 'pre_send']:
        for hook in r.hooks[event]:
            if not callable(hook):
                raise Exception(f"Hook {hook} in {event} is not callable!")
    print("  All hooks are callable")
except Exception as e:
    print(f"✗ Mixed hooks failed: {e}")

# Test 4: Empty list (edge case)
print("\nTest 4: Empty list of hooks")
try:
    r = requests.Request('GET', 'http://httpbin.org/get', hooks={'pre_request': []})
    print("✓ Empty list works")
    print(f"  Hooks registered: {r.hooks['pre_request']}")
except Exception as e:
    print(f"✗ Empty list failed: {e}")

print("\n" + "="*50)
print("All tests completed!")

